const calls = $input.all() || [];

const totalCalls = calls.length;

let positiveCalls = 0;
let negativeCalls = 0;
let neutralCalls = 0;

let totalDurationMinutes = 0;

const categoryStats = {};

for (const call of calls) {

  const tone = (call.json?.tone || "").toLowerCase();

  const category =
    call.json?.category || "unknown";

  // duration вже у хвилинах
  const durationMinutes =
    Number(call.json?.call_duration || 0);

  totalDurationMinutes += durationMinutes;

  if (tone === "positive") positiveCalls++;
  else if (tone === "negative") negativeCalls++;
  else if (tone === "neutral") neutralCalls++;

  if (!categoryStats[category]) {

    categoryStats[category] = {
      count: 0,
      totalDurationMinutes: 0
    };

  }

  categoryStats[category].count++;

  categoryStats[category].totalDurationMinutes += durationMinutes;

}

const averageDurationMinutes =
  totalCalls === 0
    ? 0
    : Number(
        (totalDurationMinutes / totalCalls)
          .toFixed(2)
      );

const categorySummary =
  Object.entries(categoryStats).map(
    ([category, data]) => ({

      category,

      count: data.count,

      averageDurationMinutes:
        Number(
          (
            data.totalDurationMinutes /
            data.count
          ).toFixed(2)
        )

    })
  );

const negativeCallPercent =
  totalCalls === 0
    ? 0
    : Math.round(
        (negativeCalls / totalCalls) * 100
      );

return [
  {
    json: {

      totalCalls,

      positiveCalls,

      negativeCalls,

      neutralCalls,

      negativeCallPercent,

      averageDurationMinutes,

      categories: categorySummary

    }
  }
];
